"""Business logic services."""

from models import User, Product, Order, BaseEntity


class EntityService:
    """Generic service for all entities."""

    def __init__(self, db):
        self.db = db

    def save(self, entity):
        """Save any entity to the database."""
        if not isinstance(entity, BaseEntity):
            raise TypeError("Expected a BaseEntity instance")
        data = entity.to_dict()
        collection = type(entity).__name__.lower() + "s"
        self.db.insert(collection, data)
        return data

    def find_by_id(self, entity_class, entity_id):
        """Find an entity by its ID."""
        collection = entity_class.__name__.lower() + "s"
        return self.db.find(collection, {"entity_id": entity_id})

    def find_all(self, entity_class, filters=None):
        """Find all entities matching filters."""
        collection = entity_class.__name__.lower() + "s"
        return self.db.find_all(collection, filters or {})

