def test_entity_service_saves():
    class MockDB:
        def __init__(self): self.data = {}
        def insert(self, coll, doc):
            self.data.setdefault(coll, []).append(doc)
        def find(self, coll, q): return None
        def find_all(self, coll, q): return self.data.get(coll, [])
    db = MockDB()
    svc = EntityService(db)
    u = User("u1", "Alice", "alice@example.com")
    svc.save(u)
    assert len(db.data.get("users", [])) == 1
    return True
